#!/usr/bin/env bash
# evidence.sh — Evidence 决策助手 for 语音转文字 (ASR).
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="语音转文字 (ASR)"
TOPIC="Evidence"

usage() {
  cat <<EOF
evidence.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 7 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./evidence.sh             # interactive
  ./evidence.sh --dry-run   # walk through but no file
  ./evidence.sh --json      # JSON to stdout
  ./evidence.sh --explain   # show backing playbook rules + mental models
  ./evidence.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 Evidence 主题下的 playbook 规则组合成交互树。

基于 7 条规则:
  • 如果 先定不可能三角的优先级，再选方案 → 则 ：明确这个场景牺牲准确率/延迟/成本哪个角，三选二。案例：会议纪要 App 要便宜 + 离线、可容忍稍低准确率 → 端侧
  • 如果 选型必在自有数据 A/B，不信厂商自报 WER → 则 ：用真实目标数据测 WER/CER × RTF × $/hr。案例：某云 API 自报 5% WER，在你带口音/噪声的
  • 如果 成本优化三件套：端侧免费 / 批量大包 / VAD 裁静音 → 则 ：按时长计费先裁掉静音空白。案例：长录音里一半是静音 → 上传前 Silero VAD 裁掉，云 API 账单近乎腰斩。
  • 如果 实时场景用流式专用引擎，离线高准用批量大模型 → 则 ：要低延迟用 RNN-T/Conformer/Deepgram Flux；要高准确用 Whisper 批量。案例：直播实
  • 如果 高风险场景防幻觉 → 则 ：静音/噪声段加 VAD 门控 + 置信度过滤，Whisper 别裸用。案例：医疗转写在每段前做 VAD，空白段不喂模型
  • 如果 移动端 Android 系统引擎不可靠 → 默认带端侧回退 → 则 ：Android SpeechRecognizer 各厂表现不一，默认集成 sherpa-onnx 兜底。案例：海外安卓
  • 如果 后处理别省，原始 ASR 输出不能直接给用户 → 则 ：VAD → 转写 → 标点恢复 → ITN(数字/单位规整) → diarization → 时间戳。案例：会议纪要直

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "先定不可能三角的优先级，再选方案"
  "选型必在自有数据 A/B，不信厂商自报 WER"
  "成本优化三件套：端侧免费 / 批量大包 / VAD 裁静音"
  "实时场景用流式专用引擎，离线高准用批量大模型"
  "高风险场景防幻觉"
  "移动端 Android 系统引擎不可靠 → 默认带端侧回退"
  "后处理别省，原始 ASR 输出不能直接给用户"
)
declare -a RULE_ACTIONS=(
  "：明确这个场景牺牲准确率/延迟/成本哪个角，三选二。案例：会议纪要 App 要便宜 + 离线、可容忍稍低准确率 → 端侧 whisper.cpp，而不是追最准的云模型。evidence: [T06-S001, T04-S002]"
  "：用真实目标数据测 WER/CER × RTF × \$/hr。案例：某云 API 自报 5% WER，在你带口音/噪声的数据上实测 15% → 直接换。evidence: [T04-S016, T02-S002]"
  "：按时长计费先裁掉静音空白。案例：长录音里一半是静音 → 上传前 Silero VAD 裁掉，云 API 账单近乎腰斩。evidence: [T03-S005, T06-S001]"
  "：要低延迟用 RNN-T/Conformer/Deepgram Flux；要高准确用 Whisper 批量。案例：直播实时字幕用流式引擎（<500ms），而不是 Whisper（非流式、慢）。evidence: [T04-S003, T03-S002]"
  "：静音/噪声段加 VAD 门控 + 置信度过滤，Whisper 别裸用。案例：医疗转写在每段前做 VAD，空白段不喂模型，避免编造病情文本。evidence: [T04-S002, T03-S006]"
  "：Android SpeechRecognizer 各厂表现不一，默认集成 sherpa-onnx 兜底。案例：海外安卓机无 Google 服务 → 系统 ASR 失效，靠内置 sherpa-onnx 仍可离线转写。evidence: [T03-S004, T02-S001]"
  "：VAD → 转写 → 标点恢复 → ITN(数字/单位规整) → diarization → 时间戳。案例：会议纪要直接给原始无标点文本不可读 → 接标点恢复 + 说话人分离才可用。evidence: [T03-S006, T04-S002]"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "evidence-decision"
fi
